  console.log(&#39;Hello, I am &#39; + this.name);
  console.log(&#39;My number is &#39; + args[0]);
&#125;

sayHi.apply(cat, [&#39;1&#39;]);
sayHi.apply(dog, [&#39;2&#39;]);

&#x2F;&#x2F; console

&#39;Hello, I am Doraemon&#39;;
&#39;My number is 1&#39;;
&#39;Hello, I am shiba&#39;;
&#39;My number is 2&#39;;

bind (常用)在執行函式前，綁定要指定的物件，這樣 this 就會是這個物件。
let cat &#x3D; &#123;
  name: &#39;Doraemon&#39;,
&#125;;

