sayHi.bind(dog)(); &#x2F;&#x2F; &quot;Hello, I am shiba&quot;

或
var obj &#x3D; &#123;
  msg &#x3D; &#39;Hello!&#39;,
&#125;

setTimeout(function() &#123;
  console.log(this.msg);
&#125;.bind(obj), 2000);

硬綁定（Hard Binding）硬綁定是指使用 &#x3D;&#x3D;bind&#x3D;&#x3D; 寫死要綁定的物件，可避免函式呼叫時退回到預設綁定。
如下，這裡有一個簡易的綁定 this 的 helper，用來寫死要綁定的物件 obj。
function today(day) &#123;
  console.log(this.todayNumber.day);
  return this.todayNumber + day;
&#125;

&#x2F;&#x2F; 簡易的綁定 this 的 helper
function bind(fn, obj) &#123;
  return function () &#123;
    return fn.apply(obj, arguments);
  &#125;;
&#125;

var obj &#x3D; &#123;
  todayNumber: 2,
&#125;;

var bar &#x3D; bind(today, obj);
var b &#x3D; bar(3);

switch (b) &#123;
  case 3:
    console.log(b);
    console.log(&quot;Today is Wednesday&quot;);
    break;

  case 5:
    console.log(b);
    console.log(&quot;Today is  Friday&quot;);

    break;
  default:
    console.log(&quot;error&quot;);
&#125;

&#x2F;&#x2F; undefined
&#x2F;&#x2F; 5
&#x2F;&#x2F; Today is Friday

在bind(today, obj) 中，

將 today 的 this 強制指定為 obj，並將結果指定給 bar，
因此當執行 bar(3) 時，this.todayNumber 對 obj 查找屬性 todayNumber（找到為 2，並非退回到全域範疇），
且加上傳入的數字 3，
而得到結果 b 為 5。

