判斷使用者 input 輸入值判斷是大還是小


function closureGo (x)&#123;
    &#x2F;&#x2F; var x &#x3D; 10
    return function hi(inputNumber)&#123;
        &#x2F;&#x2F; console.log(x + inputNumber)
        if(x &gt; inputNumber)
            console.log(&#39;Big&#39;)
        else(x &lt; inputNumber)
            console.log(&#39;Small&#39;)
