防止 var 全域變數汙染


for (var i &#x3D; 1; i &lt; 10; i++)&#123;
    (function(i)&#123;
        setTimeout(function()&#123;
            console.log(&quot;setTimeout i :&quot;,i)
        &#125;,1000)
    &#125;)(i);
&#125;

模組模式（Module Pattern）模組模式（module pattern）又稱為揭露模組（revealing module），經由建立一個模組實體（module instance，如下範例的 foo），來調用內層函式 doSomething 和 doAnother。而內層函式由於具有閉包的特性，因此可存取外層的變數和函式（something 與 another）。透過模組模式，可隱藏私密資訊，並選擇對外公開的 API。
function CoolModule() &#123;
  var something &#x3D; &#39;cool&#39;;
  var another &#x3D; [1, 2, 3];

  function doSomething() &#123;
    console.log(something);
  &#125;

  function doAnother() &#123;
    console.log(another.join(&#39; ! &#39;));
  &#125;

  return &#123;
    doSomething: doSomething,
    doAnother: doAnother,
  &#125;;
&#125;

var foo &#x3D; CoolModule();

foo.doSomething(); &#x2F;&#x2F; cool
foo.doAnother(); &#x2F;&#x2F; 1 ! 2 ! 3

以上這個例子並不難理解，它等於就是本文開頭 foo、bar 和 baz 的變形而已。
模組模式的另一個變形是 singleton- 包上 IIFE，用於只想要產生單一實體的時候，修改上例如下。
var foo &#x3D; (function CoolModule() &#123;
  var something &#x3D; &#39;cool&#39;;
  var another &#x3D; [1, 2, 3];

  function doSomething() &#123;
    console.log(something);
  &#125;

  function doAnother() &#123;
    console.log(another.join(&#39; ! &#39;));
  &#125;

  return &#123;
    doSomething: doSomething,
    doAnother: doAnother,
  &#125;;
&#125;)();

foo.doSomething(); &#x2F;&#x2F; cool
foo.doAnother(); &#x2F;&#x2F; 1 ! 2 ! 3

模組依存性載入器（Module Dependency Loader）既然我們知道了怎麼撰寫模組，那麼，要怎麼管理多個模組呢？像是在模組中引用其他模組時，可能會因程式碼放置的順序不對、產生相依性問題而導致出錯，該怎麼辦呢？
這裡提出兩個解法-使用模組依存性載入器或 ES6 模組，先來看前者。
模組依存性載入器或管理器（module dependency loader &#x2F; manager）是指將模組定義的模式包裝成一個友善的 API。範例如下，這是一個簡單的模組依存性載入器。
var MyModules &#x3D; (function Manager() &#123;
  var modules &#x3D; &#123;&#125;;

  function define(name, deps, impl) &#123;
    for (var i &#x3D; 0; i &lt; deps.length; i++) &#123;
      deps[i] &#x3D; modules[deps[i]]; &#x2F;&#x2F; (1)
    &#125;
    modules[name] &#x3D; impl.apply(null, deps); &#x2F;&#x2F; (2)
  &#125;

  function get(name) &#123;
    return modules[name];
  &#125;

  return &#123;
    define: define,
    get: get,
  &#125;;
&#125;)();

說明如下，在 Manager 這個 IIFE 裡面包含了一些變數和函式…

變數 modules 存放各個模組所公開的 API，例如：bar 的 hello、foo 的 awesome。
函式 define 輸入三個參數:
name、deps 與 impl，name 是模組名稱；
deps 是與此模組相依的模組，以陣列方式傳入；
impl 是用於定義一個外層包裹函式以建立範疇，讓其內的函式能指向這個範疇而產生閉包，最後這個函式 impl 會回傳公開 API 。


標註 (1) 的部份：deps 本來是儲存相依模組名稱的陣列，在這裡改為存放這個相依模組名稱的公開 API。例如：deps 的內容是 [&#39;bar&#39;]，deps[0] 的內容是 ‘bar’，因此deps[0] = modules[deps[0]]可看成是 bar = modules[&#39;bar&#39;]，modules[‘bar’] 以物件方式儲存 bar 的公開 API，例如：hello 和 world，即是 bar = modules[&#39;bar&#39;] = &#123;hello: ƒ, world: ƒ&#125;。
標註 (2) 的部份：這裡為模組呼叫定義了一個包裹器函式，用來將回傳值（這個值是指模組的 API）存入以名稱來當作參考的一個模組清單。此模組 impl 會傳入兩個參數，第一個參數是這個函式所要使用的 this 的值，因為在這裡不用 this 所以傳入 null 也是可以的；第二個參數是將相依的模組（與其公開 API）都傳進去，讓這個模組能夠使用其他模組的公開 API。


get 會依照輸入的模組名稱以物件形式取得其公開的 API，之後就可以指定給特定變數，然後利用這個變數使用存取屬性的方式呼叫這些 API。

以下是示範如何定義模組…關於模組 foo 與 bar，就依照以上規格分別定義之，即可使用這樣的模組依存性載入器管理多個模組了。
&#x2F;&#x2F; bar 沒有需要任何其他的模組...
MyModules.define(&#39;bar&#39;, [], function barImpl() &#123;
  function hello(who) &#123;
    return &#39;Let me introduce: &#39; + who;
  &#125;

  function world() &#123;
    return &#39;Hello World&#39;;
  &#125;

  return &#123;
    hello: hello,
  &#125;;
&#125;);

&#x2F;&#x2F; foo 需要 bar 模組...
MyModules.define(&#39;foo&#39;, [&#39;bar&#39;], function fooImpl(bar) &#123;
  var hungry &#x3D; &#39;hippo&#39;;

  function awesome() &#123;
    console.log(bar.hello(hungry).toUpperCase());
  &#125;

  return &#123;
    awesome: awesome,
  &#125;;
&#125;);

var bar &#x3D; MyModules.get(&#39;bar&#39;);
var foo &#x3D; MyModules.get(&#39;foo&#39;);

console.log(bar.hello(&#39;hippo&#39;)); &#x2F;&#x2F; Let me introduce: hippo

foo.awesome(); &#x2F;&#x2F; LET ME INTRODUCE: HIPPO

這樣就可以要用什麼就指定什麼，不用擔心順序問題了。
ES6 模組（ES6 Module）
在 ES6 中可將個別載入的檔案視為一個模組，每個模組都能匯入（import）其他模組或指定特定的 API 成員，也能匯出（export）自己公開的 API 成員。而瀏覽器或 JavaScript 引擎會經由其內建的模組載入器匯入這個模組檔案。這些模組檔案的內容可視為被包覆在一個閉包內，當被另一個檔案引入和使用時即可在非原先語彙範疇定義處正常運作。
範例如下，在 foo.js 中載入 bar module 的 hello，並用於其內的 awesome 中，以將結果字串轉為大寫；在 baz.js 載入 foo 與 bar 的完整模組，分別執行 bar.hello 與 foo.awesome()。

bar.js

function hello(who) &#123;
  return &#96;Let me introduce: $&#123;who&#125;&#96;;
&#125;

export hello;


foo.js

import hello from &#39;bar&#39;; &#x2F;&#x2F; 只會載入 bar module 的 hello

var hungry &#x3D; &#39;hippo&#39;;

function awesome() &#123;
  console.log(
    hello(hungry).toUpperCase()
  );
&#125;

export awesome;


baz.js

&#x2F;&#x2F; 載入 foo 與 bar 的完整模組
module foo from &#39;foo&#39;;
module bar from &#39;bar&#39;;

console.log(
  bar.hello(&#39;rhino&#39;)
); &#x2F;&#x2F; Let me introduce: rhino

foo.awesome(); &#x2F;&#x2F; LET ME INTRODUCE: HIPPO

這樣就可以要用什麼就載入什麼，不用擔心同名、順序等問題。
注意！模組模式是以函式為基礎來實作的，因此其 API 是在執行時期才能被識別，所以可在執行時期修改模組內的私有變數和函式；而 ES6 的模組是靜態的，意即在編譯時期而非執行時期被識別，因此可在編譯時檢查 API 是否存在而丟出錯誤訊息，並且無法在執行時修改模組內的私有變數和函式。
學到的知識點看完這篇文章，我們到底有什麼收穫呢？藉由本文可以理解到…

閉包是函式記得並存取語彙範疇的能力，可說是指向特定範疇的參考，因此當函式是在其宣告的語彙範疇之外執行時也能正常運作。
迴圈與閉包搭配使用時的謬誤與陷阱。
模組模式可經由建立一個模組實體來調用內層函式，而內層函式由於具有閉包的特性，因此可存取外層的變數和函式。透過模組模式，可隱藏私密資訊，並選擇對外公開的 API。
利用模組依存性載入器或管理器或 ES6 模組來管理模組

