Localstorage: ToDoListDemo說明專案概要
輸入內容
點擊加入待辦事項
下方依照順序列出待辦事項，並可以點擊刪除


&lt;input type&#x3D;&quot;text&quot; class&#x3D;&quot;textClass&quot; placeholder&#x3D;&quot;請填寫代辦內容&quot; &#x2F;&gt;
&lt;input type&#x3D;&quot;button&quot; class&#x3D;&quot;addList&quot; value&#x3D;&quot;加入代辦&quot; &#x2F;&gt;
&lt;ul class&#x3D;&quot;list&quot;&gt;&lt;&#x2F;ul&gt;

特別注意幾點
一開始要給待辦事項清單一個空陣列，避免爆錯誤
一開始就需要更新一次清單
儲存與刪除清單時都要先將陣列轉為字串再 setItem 進 localstorage
待辦事項清單在新增或刪除後已經是以字串的方式儲存，要調用的時候要先轉回原本陣列型別

&#x2F;&#x2F; 綁定dom
var list &#x3D; document.querySelector(&quot;.list&quot;);
var addList &#x3D; document.querySelector(&quot;.addList&quot;);
&#x2F;&#x2F; 待辦事項清單在新增或刪除後已經是以字串的方式儲存，要調用的時候要先轉回原本陣列型別
var data &#x3D; JSON.parse(localStorage.getItem(&quot;toDoList&quot;)) || [];

&#x2F;&#x2F; 監聽與更新
addList.addEventListener(&quot;click&quot;, saveItem);
list.addEventListener(&quot;click&quot;, deleteItem);
updateList(data);

&#x2F;&#x2F; 加入列表,並同步更新網頁與localStorage
function saveItem(e) &#123;
  e.preventDefault();
  var str &#x3D; document.querySelector(&quot;.textClass&quot;).value;
&#x2F;&#x2F; 避免沒輸入資料，就按新增
    if (str.trim() &#x3D;&#x3D;&#x3D; &quot;&quot;) &#123;
    alert(&quot;請輸入事項&quot;);
  &#125;
&#x2F;&#x2F; 把輸入的內容設為物件並push到data陣列中
  var todo &#x3D; &#123;
    content: str,
  &#125;;
  data.push(todo);
  &#x2F;&#x2F; 加入陣列後需要更新清單
  updateList(data);
  &#x2F;&#x2F; 更新後將資料轉為字串存到 localstorage
  localStorage.setItem(&quot;toDoList&quot;, JSON.stringify(data));
&#125;

&#x2F;&#x2F; 更新網頁內容
function updateList(items) &#123;
  str &#x3D; &quot;&quot;;
  var len &#x3D; items.length;
  for (var i &#x3D; 0; i &lt; len; i++) &#123;
    str +&#x3D;
      &#39;&lt;li&gt;&lt;a href&#x3D;&quot;#&quot; data-index&#x3D;&#39; +
      i +
      &quot;&gt;刪除&lt;&#x2F;a&gt; &lt;span&gt;&quot; +
      items[i].content +
      &quot;&lt;&#x2F;span&gt;&lt;&#x2F;li&gt;&quot;;
  &#125;
  list.innerHTML &#x3D; str;
&#125;

&#x2F;&#x2F; 刪除待辦事項
function deleteItem(e) &#123;
  e.preventDefault();
  &#x2F;&#x2F; 確認點擊的位置是 a 連結也就是&quot;刪除&quot;
  if (e.target.nodeName !&#x3D;&#x3D; &quot;A&quot;) &#123;
    return;
  &#125;
  var index &#x3D; e.target.dataset.index;
  &#x2F;&#x2F; 依照index的位置刪除 1 個 item
  data.splice(index, 1);
  localStorage.setItem(&quot;toDoList&quot;, JSON.stringify(data));
  updateList(data);
&#125;

