  background: $&#123;props &#x3D;&gt; (props.primary ? &#39;pink&#39; : &#39;blue&#39;)&#125;;
  color: $&#123;props &#x3D;&gt; (props.primary ? &#39;white&#39; : &#39;green&#39;)&#125;;
  &amp;:hover &#123;
    background: gray;
